import React, { useState } from "react";
import { Card, CardContent, TextField, Button, Typography } from "@mui/material";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";
const AddHealthInsurance = () => {
    const [name, setName] = useState("");
    const [bhytCode, setBhytCode] = useState("");
    const navigate = useNavigate();

    const handleSubmit = (e) => {
        e.preventDefault();
        console.log("New BHYT: ", { name, bhytCode });
        navigate("/admin/bhyt");
    };

    return (
        <Card>
            <CardContent>
                <Typography variant="h5">Thêm Bảo Hiểm Y Tế</Typography>
                <form onSubmit={handleSubmit}>
                    <TextField
                        label="Họ Tên"
                        variant="outlined"
                        fullWidth
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        style={{ margin: "10px 0" }}
                    />
                    <TextField
                        label="Mã BHYT"
                        variant="outlined"
                        fullWidth
                        value={bhytCode}
                        onChange={(e) => setBhytCode(e.target.value)}
                        style={{ margin: "10px 0" }}
                    />
                    <Button type="submit" variant="contained" color="primary" fullWidth>
                        Lưu
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
};

export default AddHealthInsurance;
